function ModelGameHelperAlleviation:GetGameHelperSettingServerDataListByFunctionId(functionId)
	local gameHelperSettingList = self:GetGameHelperSettingList()
	if not gameHelperSettingList then return {} end
	local refIdList = self:GetLighteningHelperSetRefIdListByFunctionId(functionId)
	if not refIdList then return {} end
	local serverDataList = {}
	local serverData
	for i,v in ipairs(refIdList) do
		serverData = gameHelperSettingList[v.refId]
		if serverData then
			table.insert(serverDataList,serverData)
		end
	end
	return serverDataList
end

--[[
	SettingInfo协议moreInfo字段说明{
		1.水晶湖
			refId = 104-108 时：免费次数
		2.试炼之藤
			refId = 109 时：免费次数
	}
]]
function ModelGameHelperAlleviation:SettingInfoDisposeMoreInfo(serverData)
	if not serverData then return end
	local refId = serverData.refId
	if StructSettingInfo.FUNCTION_1_FREE_MAP[refId] or StructSettingInfo.FUNCTION_2_FREE_MAP[refId] then
		local moreInfo = serverData.moreInfo
		if string.isempty(moreInfo) then return end
		return {
			freeNum = tonumber(moreInfo) or 0,
		}
	end
	if StructSettingInfo.FUNCTION_3_FREE_MAP[refId] then
		return {
			freeNum = serverData.maxLimit,
		}
	end
	if refId == StructSettingInfo.HELPERSET_113 then
		local moreInfo = serverData.moreInfo
		if string.isempty(moreInfo) then return end
		moreInfo = string.split(moreInfo,"|")
		return {
			freeNum = tonumber(moreInfo[1]),
			remainingFreeNum = tonumber(moreInfo[2]),
		}
	end
end

function ModelGameHelperAlleviation:ExecuteResultDisposeMoreInfoKey(serverData)
	if not serverData then return end
	local moreInfos = serverData.moreInfos
	if #moreInfos < 1 then return end
	local refId = serverData.refId
	local isWish = StructSettingInfo.WISH_MAP[refId] or false
	local moreInfoIdxMap = {}
	if isWish then
		local itemType,itemId
		for i,v in ipairs(moreInfos) do
			local map = {}
			for idx,val in ipairs(v) do
				itemType = val.itemType
				local itemTypeList = map[itemType]
				if not itemTypeList then
					itemTypeList = {}
					map[itemType] = itemTypeList
				end
				itemId = val.itemId
				itemTypeList[itemId] = val.rate
			end
			moreInfoIdxMap[i] = map
		end
	end
	return moreInfoIdxMap
end


