--- req

---	设置助手
function ModelGameHelperAlleviation:OnGameHelperSettingReq(pageRefId,settingList)
	local pb = LProtoHelper.CreateProto(LProtoIds.GameHelperSettingReq)
	pb.pageRefId = pageRefId
	if settingList then
		local setting = pb.setting
		for i,v in ipairs(settingList) do
			local settingInfo = setting:add()
			settingInfo.refId = v.refId
			settingInfo.count = v.count
			settingInfo.moreInfo = v.moreInfo

			local subOptionList = v.subOptionList or {}
			for idx,val in ipairs(subOptionList) do
				local subOption = settingInfo.subOption:add()
				subOption.refId = val.subOptionRefId
				subOption.otherInfo = val.otherInfo
				subOption.condition = val.condition
			end
		end
	end
	SendMessage(pb,LProtoIds.GameHelperSettingReq)
end

---	执行
function ModelGameHelperAlleviation:OnGameHelperExecuteReq(type,helperRefIdList)
	local pb = LProtoHelper.CreateProto(LProtoIds.GameHelperExecuteReq)
	pb.type = type
	if type == ModelGameHelperAlleviation.TYPE_EXECUTE_SINGLE then
		for i,v in ipairs(helperRefIdList) do
			table.insert(pb.helperRefId,v)
		end
	end
	SendMessage(pb,LProtoIds.GameHelperExecuteReq)
end


