--- 设置助手(登陆时下发/设置成功后刷新)
function ModelGameHelperAlleviation:OnGameHelperSettingResp(pb)
	local gameHelperSettingList = self._gameHelperSettingList
	if not gameHelperSettingList then
		gameHelperSettingList = {}
		self._gameHelperSettingList = gameHelperSettingList
	end
	local serverData,refId
	local setting = pb.setting
	for i,v in ipairs(setting) do
		serverData = self:GetSettingInfoServerData(v)
		refId = serverData.refId
		gameHelperSettingList[refId] = serverData
	end
	self._gameHelperSettingList = gameHelperSettingList
end

function ModelGameHelperAlleviation:CheckIsAllFinish(list)
	if not list then
		return true
	end

	local allFinish = true
	for i,v in pairs(list) do
		if v.state ~= StructExecuteResult.STATUS_FINISH then
			allFinish = false
			break
		end
	end
	return allFinish
end

function ModelGameHelperAlleviation:GetGameHelperExecuteStatus(list)
	local allFinish = self:CheckIsAllFinish(list)
	return allFinish and ModelGameHelperAlleviation.STATUS_TYPE_END or ModelGameHelperAlleviation.STATUS_TYPE_RUN
end

--- 执行结果
function ModelGameHelperAlleviation:OnGameHelperExecuteResp(pb)
	if LOG_INFO_ENABLED then
		printInfoNR("打印而已，莫慌       GameHelperExecuteResp")
	end

	--- local syncType = pb.syncType
	--- ModelGameHelperAlleviation.EXECUTE_1 = 1					--- 执行时返回，此时大部分结果都是进行中
	--- ModelGameHelperAlleviation.EXECUTE_2 = 2					--- 刷新某个refId的执行结果,执行后结果陆续下发
	--- ModelGameHelperAlleviation.EXECUTE_3 = 3					--- 所有结果（如登陆时下发）


	local gameHelperExecuteList = self._gameHelperExecuteList
	if not gameHelperExecuteList then
		gameHelperExecuteList = {}
		self._gameHelperExecuteList = gameHelperExecuteList
	end

	local results = pb.results
	local refId
	for i,v in ipairs(results) do
		refId = v.refId
		local recordData = gameHelperExecuteList[refId]
		if not recordData then
			recordData = StructExecuteResult:New()
		end
		recordData:CreateByPb(v)
		recordData:DisposeFightReports(v.fightReports)
		gameHelperExecuteList[refId] = recordData
	end

	local syncType = pb.syncType
	if syncType == ModelGameHelperAlleviation.EXECUTE_1 then
		self:OpenAlleviationExecuteResultWnd({
			wndType = 3,
		})
	end

	if #results > 0 then
		self:ShowNoticesItem(true,true)
	end
end

function ModelGameHelperAlleviation:ShowNoticesItem(isShow,limit)
	local noticeEnum = ModelGeneral.NOTICE_HELPERLIGHTENING
	if isShow then
		if limit then
			gModelGeneral:GetSetNoticeListItem(noticeEnum)
		else
			if not gModelGeneral:CheckIsExistNoticeItem(noticeEnum) then
				gModelGeneral:GetSetNoticeListItem(noticeEnum)
			end
		end
	else
		gModelGeneral:SetDeleteNoticeListItem(noticeEnum)
	end
	if LOG_INFO_ENABLED then
		if isShow then
			printInfoNR("====== 开启通知")
		else
			printInfoNR("====== 关闭通知")
		end
	end
end

--- 助手当前正在执行的功能玩法
function ModelGameHelperAlleviation:OnGameHelperRunningFunctionResp(pb)
	local gameHelperRunningFunctionList = self._gameHelperRunningFunctionList
	if not gameHelperRunningFunctionList then
		gameHelperRunningFunctionList = {}
		self._gameHelperRunningFunctionList = gameHelperRunningFunctionList
	end
	local stage = pb.stage
	local functionEnum = pb.functionEnum
	gameHelperRunningFunctionList[functionEnum] = {
		functionEnum = functionEnum,
		stage = stage,
		otherInfo = pb.otherInfo,
	}
	self:RunGameHelperRunningFunction(functionEnum)
end

function ModelGameHelperAlleviation:GetGameHelperRunningFunctionStage(functionEnum)
	local gameHelperRunningFunctionList = self._gameHelperRunningFunctionList
	if not gameHelperRunningFunctionList then return ModelGameHelperAlleviation.GAMEHELPERFUNCTION_STAGE_0 end
	local gameHelperRunningFunction = gameHelperRunningFunctionList[functionEnum]
	if not gameHelperRunningFunction then return ModelGameHelperAlleviation.GAMEHELPERFUNCTION_STAGE_0 end
	return gameHelperRunningFunction.stage or ModelGameHelperAlleviation.GAMEHELPERFUNCTION_STAGE_0
end

function ModelGameHelperAlleviation:CheckGameHelperRunningFunctionIsLimit(functionEnum)
	local stage = self:GetGameHelperRunningFunctionStage(functionEnum)
	return stage == ModelGameHelperAlleviation.GAMEHELPERFUNCTION_STAGE_1
end

function ModelGameHelperAlleviation:CheckGameHelperRunningFunctionIsEnd(functionEnum)
	local stage = self:GetGameHelperRunningFunctionStage(functionEnum)
	return stage == ModelGameHelperAlleviation.GAMEHELPERFUNCTION_STAGE_2
end

function ModelGameHelperAlleviation:CheckGameHelperRunningFunctionIsDefault(functionEnum)
	local stage = self:GetGameHelperRunningFunctionStage(functionEnum)
	return stage == ModelGameHelperAlleviation.GAMEHELPERFUNCTION_STAGE_0
end

function ModelGameHelperAlleviation:IgnoreRunningType(functionEnum)
	if self:CheckGameHelperRunningFunctionIsEnd(functionEnum) or self:CheckGameHelperRunningFunctionIsDefault(functionEnum) then
		return true
	end
	return false
end

function ModelGameHelperAlleviation:RunGameHelperRunningFunction(functionEnum)
	if not self:CheckGameHelperRunningFunctionIsLimit(functionEnum) then
		if self:IgnoreRunningType(functionEnum) then
			--- 结束的话，重新打开助手界面
			self:OpenCurExecuteResultWndIgnore()
		end
		return
	end

	--- 状态为1，关闭界面
	GF.CloseWndByName("UIAllcutelt")
	local data = ModelGameHelperAlleviation.GAMEHELPERFUNCTION_TO_SETTINGREFID_MAP[functionEnum]
	if not data then return end

	local refId = data.refId
	local ref = self:GetLighteningHelperSetRefByRefId(refId)
	if not ref then return end

	local functionId = ref.functionId
	ref = self:GetLighteningHelperFunctionRefByRefId(functionId)
	if not ref then return end

	local jump = ref.jump
	if jump and jump > 0 then
		if LOG_INFO_ENABLED then
			printInfoNR("jumpid = " .. jump)
		end
		gModelFunctionOpen:Jump(jump)
	end
end

------- 当玩家关闭当前界面，减负助手界面操作，一键执行或执行时，先弹出已完成的通用执行界面（只能存在一个）
------- 当玩家一键执行或执行时，强行退出，再次登录时缩小窗口进行展示；此时减负助手界面操作，一键执行或执行时，先弹出已完成的通用执行界面
function ModelGameHelperAlleviation:CheckIsOpenResultWnd()
	local gameHelperExecuteList = self._gameHelperExecuteList
	if not gameHelperExecuteList then return false end
	local num = 0
	for k,v in pairs(gameHelperExecuteList) do
		num = num + 1
		if num > 0 then break end
	end
	return num > 0
end

function ModelGameHelperAlleviation:OpenCurExecuteResultWnd()
	local gameHelperExecuteList = self:GetGameHelperExecuteList()
	self:OpenAlleviationExecuteResultWnd({
		wndType = 2,
		resultExecuteList = gameHelperExecuteList,
	})
end

function ModelGameHelperAlleviation:OpenCurExecuteResultWndIgnore()
	local gameHelperExecuteList = self:GetGameHelperExecuteList()
	GF.OpenWnd("UIAllcutelt",{
		wndType = 2,
		resultExecuteList = gameHelperExecuteList,
	})
end

