function ModelGameHelperAlleviation:CheckIsSetRefMaxLimit(itemdata,newCount)
	local refId = itemdata.refId
	local setMaxLimit = self:GetLighteningHelperSetMaxLimitByRefId(refId)
	if setMaxLimit and setMaxLimit > 0 and newCount > setMaxLimit then
		local errorLimtInfo = ModelGameHelperAlleviation.ERRORCODE_LIMIT_OPTINFO_LIST[refId]
		if errorLimtInfo then
			local code = errorLimtInfo.code
			local text = self:GetLighteningHelperTextTextByRefId(code)
			if not text then
				return true
			end
			local msgDisposeFunc = errorLimtInfo.msgDisposeFunc
			if msgDisposeFunc then
				text = msgDisposeFunc(text)
			end
			GF.ShowMessage(text)
			return true
		end
	end
	return false
end

function ModelGameHelperAlleviation:ShowMessageLighteningHelperTextByRefId(itemdata,newCount)
	if not itemdata then
		return false
	end
	local refId = itemdata.refId
	local typeInfo = self:GetInitLighteningHelperSetTypeInfoByRefId(refId)
	if not typeInfo then
		return false
	end

	local settingType = typeInfo.settingType
	if settingType == ModelGameHelperAlleviation.TYPE_SET_1 then
		return false
	end
	local maxLimit = itemdata.maxLimit
	if self:CheckIsSetRefMaxLimit(itemdata,newCount) then
		return true
	end
	if maxLimit < 0 then
		---- 道具转换次数
		local consume = itemdata.consume
		local isEmpty = string.isempty(consume)
		if isEmpty then
			return true
		else
			--consume = LxDataHelper.ParseItem_4(consume)
			return false
		end
	end
	if newCount <= maxLimit then return false end
	local errorInfo = ModelGameHelperAlleviation.ERRORCODE_OPTINFO_LIST[refId]
	if not errorInfo then return false end
	local code = errorInfo.code
	local text = self:GetLighteningHelperTextTextByRefId(code)
	if not text then
		return true
	end
	local msgDisposeFunc = errorInfo.msgDisposeFunc
	if msgDisposeFunc then
		text = msgDisposeFunc(text)
	end
	GF.ShowMessage(text)
	return true
end

