function ModelGameHelperAlleviation:DisposeCodeTxt(serverData)
	if not serverData then
		if LOG_INFO_ENABLED then
			printInfoNR("==== 没有传数据")
		end
		return ""
	end
	local code = serverData.code
	if code <= StructExecuteResult.CODE_SUC then
		if LOG_INFO_ENABLED then
			printInfoNR("==== 没有错误码")
		end
		return ""
	end
	local text = self:GetLighteningHelperTextTextByRefId(code)
	local codeInfo = serverData.codeInfo
	return LUtil.GetReplacedContent(text,codeInfo)
end

function ModelGameHelperAlleviation:DisposeCodeInfoList(serverData)
	if not serverData then return {} end
	local codeInfo = serverData.codeInfo
	if string.isempty(codeInfo) then return {} end

	local code = serverData.code
	if code <= StructExecuteResult.CODE_SUC then return {} end

	--- 邮件的形式 codeInfo
	local text = self:GetLighteningHelperTextTextByRefId(code)
	local refId = serverData.refId
	local codeInfoSplitList = {}
	if refId == StructSettingInfo.HELPERSET_118 then
		local str
		local codeInfoList = string.split(codeInfo,"|")
		for i,v in ipairs(codeInfoList) do
			str = LUtil.GetReplacedContent(text,v)
			table.insert(codeInfoSplitList,str)
		end
	else
		table.insert(codeInfoSplitList,LUtil.GetReplacedContent(text,codeInfo))
	end
	return codeInfoSplitList
end

function ModelGameHelperAlleviation:ShowCodeInfoLighteningHelperTextByServerData(serverData)
	if not serverData then return end
	local code = serverData.code
	if code <= StructExecuteResult.CODE_SUC then return end
	local text = self:GetLighteningHelperTextTextByRefId(code)
	local codeInfo = serverData.codeInfo
	if string.isempty(codeInfo) then
		return text
	end
	local codeInfoSplitList = self:DisposeCodeInfoList(serverData)
	if #codeInfoSplitList < 1 then return text end
	local codeStr = table.concat(codeInfoSplitList,",")
	return codeStr
end

