--- GetInitRef
function ModelGameHelperAlleviation:GetInitLighteningHelperSetTypeInfoByRefId(refId)
	local initLighteningHelperSetTypeList = self._initLighteningHelperSetTypeList
	if not initLighteningHelperSetTypeList then
		initLighteningHelperSetTypeList = {}
		self._initLighteningHelperSetTypeList = initLighteningHelperSetTypeList
	end
	local typeInfo = initLighteningHelperSetTypeList[refId]
	if not typeInfo then
		local ref = self:GetLighteningHelperSetRefByRefId(refId)
		if ref then
			local type = ref.type
			local typeData = string.split(type,"=")
			local defaultNum
			local subOption
			local subOptionList = {}
			local subOptionMap = {}
			local subOptionRefId
			local settingType = tonumber(typeData[1])
			if settingType == ModelGameHelperAlleviation.TYPE_SET_4 then
				subOption = string.split(typeData[2],",")
				for i,v in ipairs(subOption) do
					subOptionRefId = tonumber(v)
					table.insert(subOptionList,{
						subOptionRefId = subOptionRefId,
					})
					subOptionMap[subOptionRefId] = i
				end
			else
				defaultNum = tonumber(typeData[2])
			end

			local functionOpenList = {}
			local functionOpen = string.split(ref.functionOpen,";")
			for i,v in ipairs(functionOpen) do
				v = string.split(v,"=")

				local list = {}
				local funcList = string.split(v[2],",")
				for idx,val in ipairs(funcList) do
					table.insert(list,tonumber(val))
				end
				functionOpenList[tonumber(v[1])] = list
			end


			typeInfo = {
				settingType = settingType,
				defaultNum = defaultNum,
				subOptionList = subOptionList,
				subOptionMap = subOptionMap,
				functionOpenList = functionOpenList,
			}
			initLighteningHelperSetTypeList[refId] = typeInfo
		end
	end
	return typeInfo
end

function ModelGameHelperAlleviation:GetInitLighteningHelperSetFunctionListByFunctionId(functionId)
	local initLighteningHelperSetFunctionList = self._initLighteningHelperSetFunctionList
	if not initLighteningHelperSetFunctionList then
		initLighteningHelperSetFunctionList = {}
		self._initLighteningHelperSetFunctionList = initLighteningHelperSetFunctionList
	end
	local setFunctionIdList = initLighteningHelperSetFunctionList[functionId]
	if not setFunctionIdList then
		setFunctionIdList = {}
		for k,v in pairs(GameTable.AssistantSetRef) do
			if functionId == v.functionId then
				table.insert(setFunctionIdList,v)
			end
		end
		table.sort(setFunctionIdList,function(a,b)
			return a.sort < b.sort
		end)
		initLighteningHelperSetFunctionList[functionId] = setFunctionIdList
	end
	return setFunctionIdList
end

function ModelGameHelperAlleviation:GetLighteningHelperSetRefIdByFunctionId(functionId)
	local initSettingRefIdMap = self._initSettingRefIdMap
	if not initSettingRefIdMap then
		initSettingRefIdMap = {}
		self._initSettingRefIdMap = initSettingRefIdMap
	end
	local setRefId = initSettingRefIdMap[functionId]
	if not setRefId then
		for k,v in pairs(GameTable.AssistantFunctionRef) do
			if v.tabId == functionId then
				setRefId = v.refId
				break
			end
		end
		initSettingRefIdMap[functionId] = setRefId
	end
	return setRefId
end

function ModelGameHelperAlleviation:GetLighteningHelperSetRefIdListByFunctionId(functionId)
	local setFunctionIdList = self:GetInitLighteningHelperSetFunctionListByFunctionId(functionId)
	if not setFunctionIdList then return {} end
	local refIdList = {}
	for i,v in ipairs(setFunctionIdList) do
		table.insert(refIdList,{
			refId = v.refId,
		})
	end
	return refIdList
end

function ModelGameHelperAlleviation:GetLighteningHelperSetRefIdMapByFunctionId(functionId)
	local setFunctionIdList = self:GetInitLighteningHelperSetFunctionListByFunctionId(functionId)
	if not setFunctionIdList then return {} end
	local refIdMap = {}
	for i,v in ipairs(setFunctionIdList) do
		refIdMap[v.refId] = v
	end
	return refIdMap
end


function ModelGameHelperAlleviation:GetInitLighteningHelperSetTabRefByRefId(refId)
	local initLighteningHelperSetTabRefMap = self._initLighteningHelperSetTabRefMap
	if not initLighteningHelperSetTabRefMap then
		initLighteningHelperSetTabRefMap = {}
		self._initLighteningHelperSetTabRefMap = initLighteningHelperSetTabRefMap
	end
	local data = initLighteningHelperSetTabRefMap[refId]
	if not data then
		local ref = self:GetLighteningHelperSetTabRefByRefId(refId)
		if ref then
			local settingInfo = string.split(ref.settingInfo,"=")

			local subOptionList = {}
			local subOption = string.split(settingInfo[3],",")
			for i,v in ipairs(subOption) do
				v = tonumber(v)
				table.insert(subOptionList,{
					index = v,
				})
			end

			local functionOpenList = {}
			local functionOpen = string.split(ref.functionOpen,";")
			for i,v in ipairs(functionOpen) do
				v = string.split(v,"=")

				local list = {}
				local funcList = string.split(v[2],",")
				for idx,val in ipairs(funcList) do
					table.insert(list,tonumber(val))
				end
				functionOpenList[tonumber(v[1])] = list
			end

			local optionTxtList = {}
			local optionTxt = string.split(ccLngText(ref.optionTxt),";")
			for i,v in ipairs(optionTxt) do
				v = string.split(v,"=")
				optionTxtList[tonumber(v[1])] = v[2]
			end

			data = {
				refId = refId,
				txt = ccLngText(ref.txt),
				typeTxt = ccLngText(ref.typeTxt),
				sort = ref.sort,
				maxLimit = ref.maxLimit,
				settingInfo = {
					settingType = tonumber(settingInfo[1]),
					defaultNum = tonumber(settingInfo[2]),
					subOptionList = subOptionList,
					functionOpenList = functionOpenList,
					optionTxtList = optionTxtList,
				},
			}
			initLighteningHelperSetTabRefMap[refId] = data
		end
	end
	return data
end
