function ModelGameHelperAlleviation:CheckIsNeedJumpMap(executeServerMap)
	local gameHelperExecuteList = executeServerMap or self:GetGameHelperExecuteList()
	if not gameHelperExecuteList then return false end

	local serverData,state
	for k,v in pairs(ModelGameHelperAlleviation.GAMEHELPERFUNCTION_TO_SETTINGREFID_MAP) do
		serverData = gameHelperExecuteList[v.refId]
		if serverData then
			state = serverData.state
			if state == StructExecuteResult.STATUS_INHAND then
				self:RunGameHelperRunningFunction(k)
				return true
			end
		end
	end
	return false
end

function ModelGameHelperAlleviation:CheckWonderlandIsAutoRun()
	return self:CheckGameHelperRunningFunctionIsLimit(ModelGameHelperAlleviation.GAMEHELPERFUNCTION_1)
end

function ModelGameHelperAlleviation:CheckDreamTripIsAutoRun()
	return self:CheckGameHelperRunningFunctionIsLimit(ModelGameHelperAlleviation.GAMEHELPERFUNCTION_2)
end

